SELECT *
FROM hf_alert_record
WHERE is_deleted = 0

    AND alert_type = #{query.alertType}


    AND alert_level = #{query.alertLevel}


    AND area_id = #{query.areaId}


    AND status = #{query.status}


    AND trigger_time >= #{query.startTime}


    AND trigger_time <= #{query.endTime}

ORDER BY create_time DESC
